import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { AuthProvider, useAuth } from "./context/AuthContext";
import LoginPage from "./pages/LoginPage";
import RegisterPage from "./pages/RegisterPage";
import ItemsPage from "./pages/ItemsPage";
import AdminPage from "./pages/AdminPage";
import Layout from "./components/Layout";

function PrivateRoute({ children }: { children: React.ReactNode }) {
  const { user } = useAuth();
  return user ? <>{children}</> : <Navigate to="/login" replace />;
}

function AdminRoute({ children }: { children: React.ReactNode }) {
  const { user } = useAuth();
  if (!user) return <Navigate to="/login" replace />;
  if (user.role !== "admin") return <Navigate to="/items" replace />;
  return <>{children}</>;
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />
          <Route
            path="/"
            element={
              <PrivateRoute>
                <Layout />
              </PrivateRoute>
            }
          >
            <Route index element={<Navigate to="/items" replace />} />
            <Route path="items" element={<ItemsPage />} />
            <Route
              path="admin"
              element={
                <AdminRoute>
                  <AdminPage />
                </AdminRoute>
              }
            />
          </Route>
          <Route path="*" element={<Navigate to="/items" replace />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}

import axios from "axios";

const api = axios.create({
  baseURL: "/api",
  withCredentials: true,
});

export default api;

import { useState, FormEvent, useEffect } from "react";
import api from "../api/client";
import type { Item } from "../pages/ItemsPage";
import "./ItemModal.css";

interface Props {
  item: Item | null;
  onSaved: (item: Item) => void;
  onClose: () => void;
}

export default function ItemModal({ item, onSaved, onClose }: Props) {
  const isEdit = !!item;
  const [name, setName] = useState(item?.name ?? "");
  const [description, setDescription] = useState(item?.description ?? "");
  const [quantity, setQuantity] = useState(String(item?.quantity ?? ""));
  const [price, setPrice] = useState(String(item?.price ?? ""));
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      const body = {
        name,
        description: description || undefined,
        quantity: Number(quantity),
        price: Number(price),
      };
      let res;
      if (isEdit) {
        res = await api.patch<Item>(`/items/${item.id}`, body);
      } else {
        res = await api.post<Item>("/items", body);
      }
      onSaved(res.data);
    } catch (err) {
      const axiosErr = err as { response?: { data?: { errors?: string[]; message?: string } } };
      const msgs = axiosErr.response?.data?.errors ?? [axiosErr.response?.data?.message ?? "Hata oluştu."];
      setError(msgs.join(" "));
    } finally {
      setLoading(false);
    }
  }

  // ESC ile kapat
  useEffect(() => {
    function handleKey(e: KeyboardEvent) {
      if (e.key === "Escape") onClose();
    }
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [onClose]);

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="modal-card" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h2>{isEdit ? "Ürünü Düzenle" : "Yeni Ürün"}</h2>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>

        <form onSubmit={handleSubmit} className="modal-form">
          <div className="field">
            <label>Ürün Adı *</label>
            <input
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Ürün adını girin"
              required
              autoFocus
            />
          </div>
          <div className="field">
            <label>Açıklama</label>
            <input
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="İsteğe bağlı"
            />
          </div>
          <div className="field-row">
            <div className="field">
              <label>Miktar *</label>
              <input
                type="number"
                min="0"
                value={quantity}
                onChange={(e) => setQuantity(e.target.value)}
                placeholder="0"
                required
              />
            </div>
            <div className="field">
              <label>Fiyat (₺) *</label>
              <input
                type="number"
                min="0"
                step="0.01"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                placeholder="0.00"
                required
              />
            </div>
          </div>

          {error && <div className="modal-error">{error}</div>}

          <div className="modal-actions">
            <button type="button" className="btn-cancel" onClick={onClose}>
              İptal
            </button>
            <button type="submit" className="btn-save" disabled={loading}>
              {loading ? "Kaydediliyor…" : isEdit ? "Güncelle" : "Ekle"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import { Outlet, NavLink, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import "./Layout.css";

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  async function handleLogout() {
    await logout();
    navigate("/login");
  }

  return (
    <div className="layout">
      <aside className="sidebar">
        <div className="sidebar-logo">
          <span className="logo-icon">▣</span>
          <span className="logo-text">ENVANTER</span>
        </div>

        <nav className="sidebar-nav">
          <NavLink
            to="/items"
            // isActive parametresine boolean tipini açıkça tanımladık
            className={({ isActive }: { isActive: boolean }) => `nav-link ${isActive ? "active" : ""}`}
          >
            <span className="nav-icon">◈</span>
            Ürünler
          </NavLink>

          {user?.role === "admin" && (
            <NavLink
              to="/admin"
              // Aynı tip tanımını buradaki NavLink için de uyguladık
              className={({ isActive }: { isActive: boolean }) => `nav-link ${isActive ? "active" : ""}`}
            >
              <span className="nav-icon">◆</span>
              Rapor
            </NavLink>
          )}
        </nav>

        <div className="sidebar-footer">
          <div className="user-info">
            {/* user null check ekleyerek olası çalışma zamanı hatalarını önledik */}
            <div className="user-avatar">{user?.email?.[0].toUpperCase() ?? "?"}</div>
            <div className="user-details">
              <span className="user-email">{user?.email}</span>
              <span className={`user-role ${user?.role}`}>{user?.role}</span>
            </div>
          </div>
          <button className="logout-btn" onClick={handleLogout} title="Çıkış Yap">
            ⏻
          </button>
        </div>
      </aside>

      <main className="content">
        {/* Outlet, App.tsx'teki alt rotaların (ItemsPage, AdminPage) burada görünmesini sağlar */}
        <Outlet />
      </main>
    </div>
  );
}

import { createContext, useContext, useState, useEffect, ReactNode } from "react";
import api from "../api/client";

interface User {
  id: number;
  email: string;
  role: string;
}

interface AuthContextType {
  user: User | null;
  loading: boolean;
  login: (email: string, password: string) => Promise<void>;
  register: (email: string, password: string) => Promise<void>;
  logout: () => Promise<void>;
}

// eslint-disable-next-line react-refresh/only-export-components -- useAuth hook ve AuthProvider aynı dosyada bulunmak zorunda; ayrı dosyaya taşımak tüm import'ları kırar ve ek circular-dependency riski yaratır.
export const AuthContext = createContext<AuthContextType | null>(null);

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
  return ctx;
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Sayfa yenilendiğinde session kontrolü
  useEffect(() => {
    api
      .get<{ user: User }>("/auth/me")
      .then((res) => setUser(res.data.user))
      .catch(() => setUser(null))
      .finally(() => setLoading(false));
  }, []);

  async function login(email: string, password: string) {
    const res = await api.post<{ user: User }>("/auth/login", { email, password });
    setUser(res.data.user);
  }

  async function register(email: string, password: string) {
    const res = await api.post<{ user: User }>("/auth/register", { email, password });
    setUser(res.data.user);
  }

  async function logout() {
    await api.post("/auth/logout");
    setUser(null);
  }

  return (
    <AuthContext.Provider value={{ user, loading, login, register, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

