import { useState, useEffect } from "react";
import api from "../api/client";
import "./AdminPage.css";

interface Report {
  totalItems: number;
  totalUsers: number;
  totalValue: number;
}

export default function AdminPage() {
  const [report, setReport] = useState<Report | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    api
      .get<Report>("/admin/report")
      .then((res) => setReport(res.data))
      .catch(() => setError("Rapor yüklenemedi."))
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className="admin-page">
      <div className="page-header">
        <div>
          <h1 className="page-title">Yönetici Raporu</h1>
          <p className="page-sub">Sistem genelinde özet istatistikler</p>
        </div>
      </div>

      {loading ? (
        <div className="loading-state">Yükleniyor…</div>
      ) : error ? (
        <div className="error-state">{error}</div>
      ) : report ? (
        <div className="report-grid">
          <div className="stat-card accent">
            <div className="stat-label">Toplam Ürün</div>
            <div className="stat-value">{report.totalItems}</div>
            <div className="stat-icon">◈</div>
          </div>
          <div className="stat-card">
            <div className="stat-label">Kayıtlı Kullanıcı</div>
            <div className="stat-value">{report.totalUsers}</div>
            <div className="stat-icon">◉</div>
          </div>
          <div className="stat-card wide">
            <div className="stat-label">Toplam Stok Değeri</div>
            <div className="stat-value large">
              ₺{report.totalValue.toLocaleString("tr-TR")}
            </div>
            <div className="stat-icon">◆</div>
          </div>
        </div>
      ) : null}
    </div>
  );
}

import { useState, useEffect } from "react";
import { useAuth } from "../context/AuthContext";
import api from "../api/client";
import ItemModal from "../components/ItemModal";
import "./ItemsPage.css";

export interface Item {
  id: number;
  name: string;
  description: string | null;
  quantity: number;
  price: number;
  created_at: string;
  updated_at: string;
}

export default function ItemsPage() {
  const { user } = useAuth();
  const [items, setItems] = useState<Item[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [modalOpen, setModalOpen] = useState(false);
  const [editItem, setEditItem] = useState<Item | null>(null);

  const isAdmin = user?.role === "admin";

  useEffect(() => {
    async function fetchItems() {
      try {
        const res = await api.get<Item[]>("/items");
        setItems(res.data);
      } catch {
        // hata
      } finally {
        setLoading(false);
      }
    }
    fetchItems();
  }, []);

  async function handleDelete(id: number) {
    if (!window.confirm("Bu ürünü silmek istediğinizden emin misiniz?")) return;
    await api.delete(`/items/${id}`);
    setItems((prev) => prev.filter((i) => i.id !== id));
  }

  function openCreate() {
    setEditItem(null);
    setModalOpen(true);
  }

  function openEdit(item: Item) {
    setEditItem(item);
    setModalOpen(true);
  }

  function handleSaved(item: Item) {
    setItems((prev) => {
      const idx = prev.findIndex((i) => i.id === item.id);
      if (idx >= 0) {
        const next = [...prev];
        next[idx] = item;
        return next;
      }
      return [item, ...prev];
    });
    setModalOpen(false);
  }

  const filtered = items.filter(
    (item) =>
      item.name.toLowerCase().includes(search.toLowerCase()) ||
      (item.description ?? "").toLowerCase().includes(search.toLowerCase())
  );

  const totalValue = items.reduce((acc, i) => acc + i.quantity * i.price, 0);

  return (
    <div className="items-page">
      <div className="page-header">
        <div>
          <h1 className="page-title">Ürünler</h1>
          <p className="page-sub">
            {items.length} ürün · Toplam stok değeri:{" "}
            <strong>₺{totalValue.toLocaleString("tr-TR")}</strong>
          </p>
        </div>
        {isAdmin && (
          <button className="btn-primary" onClick={openCreate}>
            + Yeni Ürün
          </button>
        )}
      </div>

      <div className="search-bar">
        <span className="search-icon">⌕</span>
        <input
          type="text"
          placeholder="Ürün ara…"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {loading ? (
        <div className="loading-state">Yükleniyor…</div>
      ) : filtered.length === 0 ? (
        <div className="empty-state">
          <span>◈</span>
          <p>Ürün bulunamadı.</p>
        </div>
      ) : (
        <div className="items-table-wrap">
          <table className="items-table">
            <thead>
              <tr>
                <th>#</th>
                <th>Ürün Adı</th>
                <th>Açıklama</th>
                <th>Miktar</th>
                <th>Birim Fiyat</th>
                <th>Toplam</th>
                {isAdmin && <th>İşlemler</th>}
              </tr>
            </thead>
            <tbody>
              {filtered.map((item) => (
                <tr key={item.id}>
                  <td className="id-cell">{item.id}</td>
                  <td className="name-cell">{item.name}</td>
                  <td className="desc-cell">{item.description ?? "—"}</td>
                  <td>
                    <span
                      className={`qty-badge ${
                        item.quantity === 0
                          ? "out"
                          : item.quantity < 5
                          ? "low"
                          : "ok"
                      }`}
                    >
                      {item.quantity}
                    </span>
                  </td>
                  <td>₺{item.price.toLocaleString("tr-TR")}</td>
                  <td className="total-cell">
                    ₺{(item.quantity * item.price).toLocaleString("tr-TR")}
                  </td>
                  {isAdmin && (
                    <td className="actions-cell">
                      <button
                        className="action-btn edit"
                        onClick={() => openEdit(item)}
                      >
                        Düzenle
                      </button>
                      <button
                        className="action-btn delete"
                        onClick={() => handleDelete(item.id)}
                      >
                        Sil
                      </button>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {modalOpen && (
        <ItemModal
          item={editItem}
          onSaved={handleSaved}
          onClose={() => setModalOpen(false)}
        />
      )}
    </div>
  );
}

import { useState, FormEvent } from "react";
import { useNavigate, Link } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import "./AuthPage.css";

export default function LoginPage() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      await login(email, password);
      navigate("/items");
    } catch (err) {
      const axiosErr = err as { response?: { data?: { message?: string } } };
      setError(axiosErr.response?.data?.message ?? "Giriş başarısız.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="auth-page">
      <div className="auth-card">
        <div className="auth-brand">
          <span className="brand-icon">▣</span>
          <span className="brand-text">ENVANTER</span>
        </div>

        <h1 className="auth-title">Giriş Yap</h1>
        <p className="auth-sub">Sisteme erişmek için oturum açın.</p>

        <form onSubmit={handleSubmit} className="auth-form">
          <div className="field">
            <label>E-posta</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="ad@inventory.com"
              required
              autoFocus
            />
          </div>
          <div className="field">
            <label>Parola</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              required
            />
          </div>

          {error && <div className="auth-error">{error}</div>}

          <button className="auth-btn" disabled={loading}>
            {loading ? "Giriş yapılıyor…" : "Giriş Yap →"}
          </button>
        </form>

        <p className="auth-switch">
          Hesabınız yok mu? <Link to="/register">Kayıt ol</Link>
        </p>

        <div className="auth-hint">
          <span>admin@inventory.com / admin123</span>
          <span>user@inventory.com / user123</span>
        </div>
      </div>
    </div>
  );
}

