import express from "express";
import session from "express-session";
import connectSqlite3 from "connect-sqlite3";
import authRouter from "./modules/auth/auth.router";
import itemRouter from "./modules/item/item.router";
import adminRouter from "./modules/admin/admin.router";

const SQLiteStore = connectSqlite3(session);

const app = express();

app.use(express.json());

app.use(
  session({
    store: new (SQLiteStore as any)({ db: "sessions.db", dir: "./" }),
    secret: process.env.SESSION_SECRET ?? "fallback-secret",
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      sameSite: "lax",
      secure: process.env.NODE_ENV === "production",
      maxAge: 1000 * 60 * 60 * 24,
    },
  })
);

app.use("/api/auth", authRouter);
app.use("/api/items", itemRouter);
app.use("/api/admin", adminRouter);

app.use((req, res) => {
  res.status(404).json({ message: "Uçnokta bulunamadı." });
});

export default app;

import { Request, Response } from "express";
import { registerUser, loginUser } from "./auth.service";

export async function register(req: Request, res: Response): Promise<void> {
  try {
    const { email, password } = req.body;
    const user = await registerUser(email, password);
    res.status(201).json({ message: "Kayıt başarılı.", user });
  } catch (err: any) {
    res.status(err.status ?? 500).json({ message: err.message ?? "Sunucu hatası." });
  }
}

export async function login(req: Request, res: Response): Promise<void> {
  try {
    const { email, password } = req.body;
    const user = await loginUser(email, password);

    req.session.userId = user.id;
    req.session.role = user.role;

    res.status(200).json({ message: "Giriş başarılı.", user });
  } catch (err: any) {
    res.status(err.status ?? 500).json({ message: err.message ?? "Sunucu hatası." });
  }
}

export function logout(req: Request, res: Response): void {
  req.session.destroy((err) => {
    if (err) {
      res.status(500).json({ message: "Çıkış yapılırken hata oluştu." });
      return;
    }
    res.clearCookie("connect.sid");
    res.status(204).send();
  });
}

import { Request, Response } from "express";
import {
  getAllItems,
  getItemById,
  createItem,
  updateItem,
  deleteItem,
} from "./item.service";

export function listItems(req: Request, res: Response): void {
  try {
    const items = getAllItems();
    res.status(200).json(items);
  } catch (err: any) {
    res.status(err.status ?? 500).json({ message: err.message ?? "Sunucu hatası." });
  }
}

export function getItem(req: Request, res: Response): void {
  try {
    const item = getItemById(Number(req.params.id));
    res.status(200).json(item);
  } catch (err: any) {
    res.status(err.status ?? 500).json({ message: err.message ?? "Sunucu hatası." });
  }
}

export function createItemHandler(req: Request, res: Response): void {
  try {
    const item = createItem(req.body, req.session.userId!);
    res.status(201).json(item);
  } catch (err: any) {
    res.status(err.status ?? 500).json({ message: err.message ?? "Sunucu hatası." });
  }
}

export function updateItemHandler(req: Request, res: Response): void {
  try {
    const item = updateItem(Number(req.params.id), req.body);
    res.status(200).json(item);
  } catch (err: any) {
    res.status(err.status ?? 500).json({ message: err.message ?? "Sunucu hatası." });
  }
}

export function deleteItemHandler(req: Request, res: Response): void {
  try {
    deleteItem(Number(req.params.id));
    res.status(204).send();
  } catch (err: any) {
    res.status(err.status ?? 500).json({ message: err.message ?? "Sunucu hatası." });
  }
}
